import{_ as e,o as a,c as o,a7 as r}from"./chunks/framework.BgApuQ2e.js";const n="/images/the-death-toll-comparison-breakdown/Aztec1.png",p="/images/the-death-toll-comparison-breakdown/Deaths-Key.jpg",l="/images/the-death-toll-comparison-breakdown/DEATH1.jpg",s="/images/the-death-toll-comparison-breakdown/Death-Final41.png",h="/images/the-death-toll-comparison-breakdown/DEATH3.jpg",i="/images/the-death-toll-comparison-breakdown/pinit_fg_en_rect_gray_20.png",k=JSON.parse('{"title":"The Death Toll Comparison Breakdown","description":"","frontmatter":{"title":"The Death Toll Comparison Breakdown","titleZh":"死亡人数对比解析","date":"2013-08-05T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/08/the-death-toll-comparison-breakdown.html","slug":"the-death-toll-comparison-breakdown"},"headers":[],"relativePath":"posts/the-death-toll-comparison-breakdown.md","filePath":"posts/the-death-toll-comparison-breakdown.md","lastUpdated":1782886257000}'),m={name:"posts/the-death-toll-comparison-breakdown.md"};function c(d,t,w,g,b,_){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="死亡人数对比解析-·-the-death-toll-comparison-breakdown" tabindex="-1">死亡人数对比解析 · The Death Toll Comparison Breakdown <a class="header-anchor" href="#死亡人数对比解析-·-the-death-toll-comparison-breakdown" aria-label="Permalink to &quot;死亡人数对比解析 · The Death Toll Comparison Breakdown&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/08/the-death-toll-comparison-breakdown.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/08/the-death-toll-comparison-breakdown.html</a> · 2013-08-05</p></blockquote><p>关于人类,有一件事是他们有时会死,而人类特别关注的一件事就是别人的死。我们挺擅长把「我总有一天会死」这件事从脑子里赶出去,但那种执念一直都在,潜伏在表面之下,而它显露出来的方式之一,就是我们对别人的死总是<strong>看得入迷</strong>。</p><p>新闻就是一个明显的例子——随便打开 CNN.com,通常至少一半的头条都跟人死了有关。娱乐是另一个——没什么比一个角色的死更能把眼睛牢牢锁在屏幕上。</p><p>历史是一个不那么明显的例子,但历史上最能让我们着迷的部分,通常就是死了很多人的那些部分。这就是为什么战争电影那么多,而关于通过某项关键立法的电影那么少。</p><p>不过,对于一群这么热衷于死亡的人,人类对历史上那些关键时刻实际死亡人数的了解,少得出奇。我们大多数人知道 9/11 死了 3000 人,但有多少美国人知道卡特里娜飓风的遇难者有多少,或者美国独立战争死了多少人?基督教十字军东征的死亡人数是越南战争的 100 倍吗?还是两者死亡人数其实差不多?考虑到我们花了那么多时间谈论历史上的人类悲剧,这些数字似乎是我们应该更熟悉一点的东西。那就来看看吧。</p><p>几点快速说明:</p><ul><li><p>图中每个圆的面积与它所代表的数字、以及图中其他圆之间,是严格成比例的。请注意刻度,以及它如何随着数字增大而变化。我选了圆和面积,是因为像柱状图那样的一维刻度,在数字动辄相差 1000 倍的情况下根本没法用——你需要二维才能容纳这么宽的范围。但要记住,按面积的规律来算,一个圆的直径是另一个圆的两倍,代表的死亡人数是<strong>四倍</strong>,不是两倍。</p></li><li><p>我主要聚焦于各种各样的人类悲剧,但在其中穿插了一些普通的死亡统计数据(灰色圆圈)作为对照,帮你把事情放在合适的尺度里看。</p></li><li><p>我尽量在研究过程中保持严谨。网上有很多「资料来源」引用了各种各样的死亡人数——所以我确保下面每一个数字都有相对合理的共识。当各方观点分歧太大时(比如 Howard Zinn 说欧洲殖民主义杀了 1 亿人,另一些资料却说只有 200 万),我干脆就不列了。有时候,某个事件的确切死亡人数确实存在真实的不确定性,但对死亡人数的上下限有共识。这种情况下,我把上限画成一个大的、颜色淡的圆,把下限画成里面一个较小的、颜色亮的圆。比如,被阿兹特克人割掉心脏献祭的幸运儿总数就无从知晓。但历史学家相当确信这个数字在 30 万到 150 万之间。所以我用这样两个圆来表示:</p></li></ul><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/08/Aztec1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Aztec"></a></p><p>好了,开始正题。死亡人数对比全览:</p><h2 id="图例" tabindex="-1">图例 <a class="header-anchor" href="#图例" aria-label="Permalink to &quot;图例&quot;">​</a></h2><p><a href="https://waitbutwhy.com/wp-content/uploads/2013/08/Deaths-Key.jpg" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Deaths Key"></a></p><h2 id="" tabindex="-1"><a href="https://waitbutwhy.com/wp-content/uploads/2013/08/DEATH1.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt="DEATH1"></a><a href="https://waitbutwhy.com/wp-content/uploads/2013/08/Death-Final41.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Death Final4"></a><a href="https://waitbutwhy.com/wp-content/uploads/2013/08/DEATH3.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="DEATH3"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![DEATH1](/images/the-death-toll-comparison-breakdown/DEATH1.jpg)](https://waitbutwhy.com/wp-content/uploads/2013/08/DEATH1.jpg)[![Death Final4](/images/the-death-toll-comparison-breakdown/Death-Final41.png)](https://waitbutwhy.com/wp-content/uploads/2013/08/Death-Final41.png)[![DEATH3](/images/the-death-toll-comparison-breakdown/DEATH3.jpg)](https://waitbutwhy.com/wp-content/uploads/2013/08/DEATH3.jpg)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,可以订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><strong>______</strong></p><p><strong>更多 Wait But Why 历史科普:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">从穆罕默德到 ISIS:伊拉克的完整故事</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html" target="_blank" rel="noreferrer">美国总统们——从华盛顿到林肯</a></strong></p><p>以及另一篇信息图形式的:<strong><a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">把时间放进视角里</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/08/the-death-toll-comparison-breakdown.html&amp;description=The%20Death%20Toll%20Comparison%20Breakdown" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p>',22)])])}const f=e(m,[["render",c]]);export{k as __pageData,f as default};
